// Embedded forms — works from file:// with no server needed
const FORMS = {
  'hvac-training-checklist.html': '',
  'service-call-checklist.html': '',
}

export function openFormFile(filename) {
  const b64 = FORMS[filename]
  if (!b64) { alert('Form not found: ' + filename); return }
  try {
    const html = decodeURIComponent(escape(atob(b64)))
    const blob = new Blob([html], {type: 'text/html'})
    const url = URL.createObjectURL(blob)
    window.open(url, '_blank')
  } catch(e) {
    // fallback: data URL
    window.open('data:text/html;base64,' + b64, '_blank')
  }
}
